-- Additional word families for comprehensive phonics coverage.
-- Each family has multiple words showing the same spelling-sound pattern.
-- Idempotent: ON CONFLICT DO NOTHING.
--
-- This adds 10 new word families (total: 15) with ~150+ new words.

-- ── Word Families ─────────────────────────────────────────────────────────────

INSERT INTO word_families (id, pattern, sound, rule) VALUES

  -- Short vowel families
  ('f1000000-0000-4000-8000-000000000201', '-ack', '/æk/', 'Short a followed by ck, as in back and pack.'),
  ('f1000000-0000-4000-8000-000000000202', '-ick', '/ɪk/', 'Short i followed by ck, as in pick and stick.'),
  ('f1000000-0000-4000-8000-000000000203', '-ock', '/ɒk/', 'Short o followed by ck, as in lock and rock.'),
  ('f1000000-0000-4000-8000-000000000204', '-uck', '/ʌk/', 'Short u followed by ck, as in duck and luck.'),

  -- Long vowel magic E families
  ('f1000000-0000-4000-8000-000000000205', '-ace', '/eɪs/', 'The a_e pattern says long A, as in face and race.'),
  ('f1000000-0000-4000-8000-000000000206', '-ice', '/aɪs/', 'The i_e pattern says long I, as in ice and mice.'),
  ('f1000000-0000-4000-8000-000000000207', '-ope', '/oʊp/', 'The o_e pattern says long O, as in hope and rope.'),

  -- Long vowel teams
  ('f1000000-0000-4000-8000-000000000208', '-eam', '/iːm/', 'The ea vowel team says long E before m, as in team and steam.'),
  ('f1000000-0000-4000-8000-000000000209', '-ail', '/eɪl/', 'The ai vowel team says long A before l, as in mail and pail.'),
  ('f1000000-0000-4000-8000-000000000210', '-een', '/iːn/', 'The ee vowel team says long E before n, as in green and queen.')

ON CONFLICT (id) DO NOTHING;

